    #[doc = "Get the position of the camera in relation to the system.\n\nMost platforms will report UNKNOWN, but mobile devices, like phones, can\noften make a distinction between cameras on the front of the device (that\npoints towards the user, for taking \"selfies\") and cameras on the back (for\nfilming in the direction the user is facing).\n\n**Parameter:** instance_id the camera device instance ID.\n\n**Returns:** the position of the camera on the system hardware.\n\n**Thread Safety:** It is safe to call this function from any thread.\n\n**Available Since:** This function is available since SDL 3.2.0.\n\n**See Also:** SDL_GetCameras"]
    pub fn SDL_GetCameraPosition(instance_id: SDL_CameraID) -> SDL_CameraPosition;
