#[repr(transparent)]
#[doc = "The SDL keyboard scancode representation.\n\nAn SDL scancode is the physical representation of a key on the keyboard,\nindependent of language and keyboard mapping.\n\nValues of this type are used to represent keyboard keys, among other places\nin the `scancode` field of the SDL_KeyboardEvent structure.\n\nThe values in this enumeration are based on the USB usage page standard:\nhttps://usb.org/sites/default/files/hut1_5.pdf\n\n**Available Since:** This enum is available since SDL 3.2.0."]
#[derive(Debug, Copy, Clone, Hash, PartialEq, Eq)]
pub struct SDL_Scancode(pub core::ffi::c_uint);
#[doc = "The SDL virtual key representation.\n\nValues of this type are used to represent keyboard keys using the current\nlayout of the keyboard. These values include Unicode values representing\nthe unmodified character that would be generated by pressing the key, or an\n`SDLK_*` constant for those keys that do not generate characters.\n\nA special exception is the number keys at the top of the keyboard which map\nby default to SDLK_0...SDLK_9 on AZERTY layouts.\n\nKeys with the `SDLK_EXTENDED_MASK` bit set do not map to a scancode or\nUnicode code point.\n\nMany common keycodes are listed below, but this list is not exhaustive.\n\n**Available Since:** This datatype is available since SDL 3.2.0.\n\n**See Also:** SDL_HINT_KEYCODE_OPTIONS"]
pub type SDL_Keycode = Uint32;
#[doc = "Valid key modifiers (possibly OR'd together).\n\n**Available Since:** This datatype is available since SDL 3.2.0."]
pub type SDL_Keymod = Uint16;
#[doc = "This is a unique ID for a keyboard for the time it is connected to the\nsystem, and is never reused for the lifetime of the application.\n\nIf the keyboard is disconnected and reconnected, it will get a new ID.\n\nThe value 0 is an invalid ID.\n\n**Available Since:** This datatype is available since SDL 3.2.0."]
pub type SDL_KeyboardID = Uint32;
